import React, { useState } from 'react';
import axios from 'axios';
import SubmitionBar from "../SubmitionBar/SubmitionBar.jsx";
import Button from '../Button/Button.jsx'
import { useNavigate } from 'react-router-dom';

const API = axios.create({
    baseURL: 'http://localhost:3001'
});

const Login = ({ handleUserLogin }) => {
    const navigate = useNavigate();
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState("");

    const [logUser, setLogUser] = useState({
        email: "",
        senha: ""
    });

    const handleSubmition = (fieldName) => (value) => {
        setLogUser(prev => ({
            ...prev,
            [fieldName]: value
        }));
        setError(""); // Limpa erro quando usuário digita
    };

    const handleLogin = async () => {
        // Validação básica
        if (!logUser.email || !logUser.senha) {
            setError("Todos os campos são obrigatórios!");
            return;
        }

        setLoading(true);
        setError("");

        try {
            // Enviar dados para o backend
            const response = await API.post('/users/login', logUser);
            console.log("Resposta do servidor:", response.data);

            // Verifica se tem token na resposta
            if (response.data.token) {
                alert("Login realizado com sucesso!");
                
                // Salva token e dados do usuário
                localStorage.setItem('token', response.data.token);
                localStorage.setItem('user', JSON.stringify(response.data.user));
                
                // Chama a função do App com os dados do usuário
                handleUserLogin(response.data.user, response.data.token);
                
                // Navega para tasks
                navigate('/tasks');
            } else {
                setError(response.data.message || "Erro ao conectar-se. Tente novamente.");
            }
        } catch (error) {
            console.error("Erro no login:", error);
            setError(error.response?.data?.message || "Erro de conexão com o servidor.");
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="bg-home">
            <div className="container-registro">
                <header>Login</header>
                
                {error && <div style={{ color: 'red', marginBottom: '10px' }}>{error}</div>}
                
                <SubmitionBar 
                    handleAddition={handleSubmition("email")} 
                    type="email" 
                    placeholder="Digite seu email"
                />
                
                <SubmitionBar 
                    handleAddition={handleSubmition("senha")} 
                    type="password" 
                    placeholder="Digite sua senha"
                />
                
                <div> 
                    <Button onClick={handleLogin} disabled={loading}>
                        {loading ? "Entrando..." : "Entrar"}
                    </Button> 
                </div>
                
                <div>
                    <small>
                        Não tem conta?{" "}
                        <span 
                            style={{ color: '#d400ff', cursor: 'pointer' }} 
                            onClick={() => navigate('/registro')}
                        >
                            Registre-se
                        </span>
                    </small>
                </div>
            </div>
        </div>
    );
};

export default Login;
